INSERT INTO questions (subject, topic, difficulty, question_text, choices, correct_answer, explanation, exam_type) VALUES
('General Education','Science','easy','What is the chemical symbol for water?','[{"key":"A","text":"H₂O₂"},{"key":"B","text":"CO₂"},{"key":"C","text":"H₂O"},{"key":"D","text":"HO"}]','C','Water is H₂O — two hydrogen atoms bonded to one oxygen atom.','secondary'),
('General Education','Science','easy','The periodic table is organized by:','[{"key":"A","text":"Atomic mass"},{"key":"B","text":"Atomic number (number of protons)"},{"key":"C","text":"Alphabetical order of element names"},{"key":"D","text":"Density"}]','B','The modern periodic table organizes elements by increasing atomic number (number of protons), which corresponds to their electronic structure.','secondary'),
('General Education','Science','easy','An atom that gains or loses electrons becomes a/an:','[{"key":"A","text":"Molecule"},{"key":"B","text":"Compound"},{"key":"C","text":"Ion"},{"key":"D","text":"Isotope"}]','C','An ion is an atom or molecule that has gained or lost electrons, giving it a positive (cation) or negative (anion) charge.','secondary'),
('General Education','Science','medium','In the reaction H₂ + Cl₂ → 2HCl, what type of reaction is this?','[{"key":"A","text":"Decomposition"},{"key":"B","text":"Single replacement"},{"key":"C","text":"Double replacement"},{"key":"D","text":"Synthesis (combination)"}]','D','A synthesis reaction combines two or more reactants to form one product: A + B → AB. H₂ + Cl₂ → 2HCl is a synthesis reaction.','secondary'),
('General Education','Science','easy','Which element has the atomic number 1?','[{"key":"A","text":"Helium"},{"key":"B","text":"Carbon"},{"key":"C","text":"Hydrogen"},{"key":"D","text":"Oxygen"}]','C','Hydrogen (H) has atomic number 1 — it has 1 proton. It is the lightest and most abundant element in the universe.','secondary'),
('General Education','Science','medium','What is the law of conservation of mass?','[{"key":"A","text":"Mass can be created but not destroyed"},{"key":"B","text":"Mass cannot be created or destroyed in a chemical reaction"},{"key":"C","text":"The mass of products is always greater than reactants"},{"key":"D","text":"Elements combine in simple whole-number ratios"}]','B','The law of conservation of mass (Lavoisier) states that the total mass of reactants equals the total mass of products in any chemical reaction.','secondary'),
('General Education','Science','medium','Which subatomic particle has no charge?','[{"key":"A","text":"Proton"},{"key":"B","text":"Electron"},{"key":"C","text":"Neutron"},{"key":"D","text":"Positron"}]','C','Neutrons are electrically neutral (no charge). Protons have positive charge (+1) and electrons have negative charge (-1).','secondary'),
('General Education','Science','easy','What is the pH of a neutral solution at 25°C?','[{"key":"A","text":"0"},{"key":"B","text":"7"},{"key":"C","text":"14"},{"key":"D","text":"5"}]','B','A neutral solution has pH = 7 (like pure water). Acids have pH < 7; bases have pH > 7.','secondary'),
('General Education','Science','medium','Which type of chemical bond involves the sharing of electrons?','[{"key":"A","text":"Ionic bond"},{"key":"B","text":"Metallic bond"},{"key":"C","text":"Hydrogen bond"},{"key":"D","text":"Covalent bond"}]','D','A covalent bond involves the sharing of electron pairs between atoms. Ionic bonds involve electron transfer.','secondary'),
('General Education','Science','hard','The number of moles in 44 g of CO₂ (molar mass = 44 g/mol) is:','[{"key":"A","text":"44 moles"},{"key":"B","text":"0.44 moles"},{"key":"C","text":"1 mole"},{"key":"D","text":"2 moles"}]','C','Moles = mass/molar mass = 44 g ÷ 44 g/mol = 1 mole.','secondary'),
('General Education','Science','medium','Which of the following is a physical change?','[{"key":"A","text":"Iron rusting"},{"key":"B","text":"Wood burning"},{"key":"C","text":"Ice melting"},{"key":"D","text":"Baking a cake"}]','C','Melting ice is a physical change — only the state changes from solid to liquid; the chemical composition (H₂O) remains the same.','secondary'),
('General Education','Science','easy','What is the name of NaCl?','[{"key":"A","text":"Sodium carbonate"},{"key":"B","text":"Sodium chloride"},{"key":"C","text":"Sodium hydroxide"},{"key":"D","text":"Sodium nitrate"}]','B','NaCl is sodium chloride, commonly known as table salt. Sodium (Na) + Chloride (Cl⁻).','secondary'),
('General Education','Science','medium','The element with the symbol "Fe" is:','[{"key":"A","text":"Fluorine"},{"key":"B","text":"Francium"},{"key":"C","text":"Iron"},{"key":"D","text":"Fermium"}]','C','Fe is the chemical symbol for iron, from the Latin "ferrum." Iron has atomic number 26.','secondary'),
('General Education','Science','hard','What is the molarity of a solution containing 0.5 moles of NaOH dissolved in 250 mL of water?','[{"key":"A","text":"0.5 M"},{"key":"B","text":"1 M"},{"key":"C","text":"2 M"},{"key":"D","text":"0.25 M"}]','C','Molarity (M) = moles/volume in liters = 0.5 mol / 0.25 L = 2 M.','secondary'),
('General Education','Science','medium','Acids taste _____ and turn blue litmus paper _____.','[{"key":"A","text":"bitter; red"},{"key":"B","text":"sour; red"},{"key":"C","text":"sour; blue"},{"key":"D","text":"bitter; blue"}]','B','Acids taste sour (like vinegar), turn blue litmus paper red, have pH < 7, and release H⁺ ions in solution.','secondary'),
('General Education','Science','easy','What happens to the boiling point of water at higher altitudes?','[{"key":"A","text":"It increases because of lower air pressure"},{"key":"B","text":"It remains constant at 100°C"},{"key":"C","text":"It decreases because of lower air pressure"},{"key":"D","text":"It increases because of lower temperature"}]','C','At higher altitudes, atmospheric pressure decreases, which lowers the boiling point of water (below 100°C).','secondary'),
('General Education','Science','medium','Which type of reaction produces a precipitate (solid)?','[{"key":"A","text":"Combustion"},{"key":"B","text":"Acid-base neutralization"},{"key":"C","text":"Double replacement (precipitation) reaction"},{"key":"D","text":"Decomposition"}]','C','Double replacement (metathesis) reactions can produce a precipitate when two soluble ionic compounds react to form an insoluble product.','secondary'),
('General Education','Science','hard','Balance the equation: Fe + O₂ → Fe₂O₃','[{"key":"A","text":"2Fe + O₂ → Fe₂O₃"},{"key":"B","text":"4Fe + 3O₂ → 2Fe₂O₃"},{"key":"C","text":"Fe + O₃ → FeO₃"},{"key":"D","text":"2Fe + 3O₂ → 2Fe₂O₃"}]','B','4Fe + 3O₂ → 2Fe₂O₃: 4 Fe atoms on both sides (4 left, 2×2=4 right); 6 O atoms on both sides (3×2=6 left, 2×3=6 right).','secondary'),
('General Education','Science','medium','An element in Group 1 (alkali metals) is expected to:','[{"key":"A","text":"Be very unreactive"},{"key":"B","text":"Lose one electron to form +1 ions"},{"key":"C","text":"Gain two electrons to form -2 ions"},{"key":"D","text":"Share electrons with other metals"}]','B','Alkali metals (Group 1) have one valence electron. They readily lose this electron to form +1 cations, making them highly reactive.','secondary'),
('General Education','Science','easy','What is the charge of a proton?','[{"key":"A","text":"-1"},{"key":"B","text":"0"},{"key":"C","text":"+1"},{"key":"D","text":"+2"}]','C','A proton carries a positive charge of +1 (same magnitude but opposite sign to an electron).','secondary'),
('General Education','Science','medium','The process of a solid directly converting to gas without passing through liquid phase is called:','[{"key":"A","text":"Evaporation"},{"key":"B","text":"Condensation"},{"key":"C","text":"Sublimation"},{"key":"D","text":"Deposition"}]','C','Sublimation is the phase transition from solid directly to gas (e.g., dry ice/CO₂, iodine crystals, mothballs/naphthalene).','secondary'),
('General Education','Science','hard','Which quantum number describes the shape of an orbital?','[{"key":"A","text":"Principal quantum number (n)"},{"key":"B","text":"Angular momentum quantum number (l)"},{"key":"C","text":"Magnetic quantum number (mₗ)"},{"key":"D","text":"Spin quantum number (mₛ)"}]','B','The angular momentum (azimuthal) quantum number (l) determines the shape of the orbital: l=0 (s), l=1 (p), l=2 (d), l=3 (f).','secondary'),
('General Education','Science','medium','What is an exothermic reaction?','[{"key":"A","text":"A reaction that absorbs heat from the surroundings"},{"key":"B","text":"A reaction that releases heat to the surroundings"},{"key":"C","text":"A reaction that occurs only at high temperatures"},{"key":"D","text":"A reaction that requires light energy"}]','B','Exothermic reactions release heat to the surroundings (ΔH < 0), like combustion. Endothermic reactions absorb heat (ΔH > 0).','secondary'),
('General Education','Science','easy','Which of the following is a noble gas?','[{"key":"A","text":"Fluorine"},{"key":"B","text":"Nitrogen"},{"key":"C","text":"Neon"},{"key":"D","text":"Sodium"}]','C','Noble gases (Group 18) are chemically inert. They include Helium, Neon, Argon, Krypton, Xenon, and Radon.','secondary'),
('General Education','Science','medium','The Bohr model of the atom describes electrons as:','[{"key":"A","text":"A cloud of probability around the nucleus"},{"key":"B","text":"Moving in fixed circular orbits around the nucleus"},{"key":"C","text":"Embedded in a sea of positive charge"},{"key":"D","text":"Randomly distributed throughout the atom"}]','B','Niels Bohr (1913) proposed electrons orbit the nucleus in fixed circular energy levels (shells), absorbing or emitting energy when jumping between levels.','secondary'),
('General Education','Science','hard','The reaction between an acid and a base producing salt and water is called:','[{"key":"A","text":"Hydrolysis"},{"key":"B","text":"Oxidation"},{"key":"C","text":"Neutralization"},{"key":"D","text":"Saponification"}]','C','Neutralization: acid + base → salt + water. Example: HCl + NaOH → NaCl + H₂O.','secondary'),
('General Education','Science','medium','Which type of isomers have the same molecular formula but differ in the arrangement of atoms?','[{"key":"A","text":"Isotopes"},{"key":"B","text":"Allotropes"},{"key":"C","text":"Structural isomers"},{"key":"D","text":"Polymers"}]','C','Structural (constitutional) isomers have the same molecular formula but different connectivity/arrangement of atoms, giving different properties.','secondary'),
('General Education','Science','easy','Carbon dioxide (CO₂) is formed when:','[{"key":"A","text":"Carbon reacts with water"},{"key":"B","text":"Carbon burns completely in oxygen"},{"key":"C","text":"Carbon monoxide reacts with water"},{"key":"D","text":"Oxygen reacts with nitrogen"}]','B','Complete combustion of carbon: C + O₂ → CO₂. Incomplete combustion with limited oxygen produces CO instead.','secondary'),
('General Education','Science','medium','Which property increases from left to right across a period on the periodic table?','[{"key":"A","text":"Atomic radius"},{"key":"B","text":"Metallic character"},{"key":"C","text":"Electronegativity"},{"key":"D","text":"Atomic mass (strictly)"}]','C','Electronegativity increases left to right across a period (more protons attract electrons more strongly) and decreases going down a group.','secondary'),
('General Education','Science','hard','Calculate the percent composition of hydrogen in water (H₂O). [H=1, O=16]','[{"key":"A","text":"5.6%"},{"key":"B","text":"11.2%"},{"key":"C","text":"88.9%"},{"key":"D","text":"18%"}]','B','Molar mass of H₂O = 2(1) + 16 = 18. Mass of H = 2. % H = (2/18) × 100 ≈ 11.1%.','secondary'),
('General Education','Science','easy','The smallest unit of an element that retains its chemical properties is a/an:','[{"key":"A","text":"molecule"},{"key":"B","text":"ion"},{"key":"C","text":"atom"},{"key":"D","text":"electron"}]','C','An atom is the smallest unit of an element that retains all its chemical properties. Elements are made up of atoms of one kind.','secondary'),
('General Education','Science','medium','What is the IUPAC name of CH₃CH₂OH?','[{"key":"A","text":"Methanol"},{"key":"B","text":"Ethanol"},{"key":"C","text":"Propanol"},{"key":"D","text":"Butanol"}]','B','CH₃CH₂OH has 2 carbon atoms in the main chain with an -OH group, making it ethanol (ethyl alcohol).','secondary'),
('General Education','Science','hard','According to Le Chatelier''s Principle, if pressure is increased on the reaction N₂ + 3H₂ ⇌ 2NH₃, the equilibrium shifts:','[{"key":"A","text":"To the left (toward reactants)"},{"key":"B","text":"To the right (toward products)"},{"key":"C","text":"No change occurs"},{"key":"D","text":"The reaction stops completely"}]','B','Increasing pressure favors the side with fewer moles of gas. Left side: 1+3=4 moles gas; right side: 2 moles gas. Equilibrium shifts right to reduce pressure.','secondary'),
('General Education','Science','medium','Electrons are found in the _____ of an atom.','[{"key":"A","text":"nucleus"},{"key":"B","text":"neutron"},{"key":"C","text":"electron cloud/shells"},{"key":"D","text":"proton"}]','C','Electrons occupy regions of space called orbitals, arranged in energy levels (shells) surrounding the nucleus.','secondary'),
('General Education','Science','easy','Which of the following is a mixture (not a pure substance)?','[{"key":"A","text":"Distilled water"},{"key":"B","text":"Salt water"},{"key":"C","text":"Pure oxygen"},{"key":"D","text":"Pure gold"}]','B','Salt water is a mixture (solution) of salt (NaCl) and water. Pure substances (elements or compounds) have definite compositions.','secondary'),
('General Education','Science','medium','The activation energy of a reaction is the:','[{"key":"A","text":"Total energy released by the reaction"},{"key":"B","text":"Minimum energy needed to start the reaction"},{"key":"C","text":"Energy difference between products and reactants"},{"key":"D","text":"Heat absorbed from the surroundings"}]','B','Activation energy is the minimum energy required for reactant molecules to collide successfully and form products. Catalysts lower activation energy.','secondary'),
('General Education','Science','hard','What is the hybridization of carbon in CH₄?','[{"key":"A","text":"sp"},{"key":"B","text":"sp²"},{"key":"C","text":"sp³"},{"key":"D","text":"sp³d"}]','C','In methane (CH₄), carbon forms 4 equivalent bonds with hydrogen in a tetrahedral geometry, requiring sp³ hybridization.','secondary'),
('General Education','Science','medium','The modern quantum model of the atom replaced the Bohr model because:','[{"key":"A","text":"Bohr''s model was too mathematically complex"},{"key":"B","text":"Bohr''s model could only explain hydrogen''s spectrum; quantum mechanics explains all elements"},{"key":"C","text":"Bohr''s model denied the existence of the nucleus"},{"key":"D","text":"The quantum model is simpler to understand"}]','B','Bohr''s model successfully explained hydrogen''s spectrum but failed for multi-electron atoms. Quantum mechanics (Schrödinger equation) provides a more complete description.','secondary'),
('General Education','Science','easy','Which of the following is an example of a chemical property?','[{"key":"A","text":"Boiling point"},{"key":"B","text":"Density"},{"key":"C","text":"Flammability"},{"key":"D","text":"Color"}]','C','A chemical property describes how a substance reacts chemically. Flammability (ability to burn) is a chemical property; boiling point, density, and color are physical properties.','secondary'),
('General Education','Science','medium','What does the atomic mass number represent?','[{"key":"A","text":"Number of protons only"},{"key":"B","text":"Number of electrons"},{"key":"C","text":"Number of protons plus neutrons"},{"key":"D","text":"Number of neutrons only"}]','C','Mass number = number of protons (Z) + number of neutrons (N). It represents the total number of nucleons in the nucleus.','secondary'),
('General Education','Science','hard','Which of the following explains why diamond is harder than graphite, even though both are pure carbon?','[{"key":"A","text":"Diamond has more electrons than graphite"},{"key":"B","text":"Diamond has a 3D tetrahedral covalent network; graphite has layered 2D sheets"},{"key":"C","text":"Diamond contains iron impurities that make it hard"},{"key":"D","text":"Graphite has ionic bonds while diamond has covalent bonds"}]','B','Diamond: each C is sp³ bonded in a 3D network (very hard). Graphite: sp² bonded in 2D layers held by weak van der Waals forces (soft, slippery).','secondary'),
('General Education','Science','easy','What is the chemical formula for glucose?','[{"key":"A","text":"C₁₂H₂₂O₁₁"},{"key":"B","text":"C₆H₁₂O₆"},{"key":"C","text":"CH₄"},{"key":"D","text":"C₂H₅OH"}]','B','Glucose (blood sugar) has the molecular formula C₆H₁₂O₆. Sucrose (table sugar) is C₁₂H₂₂O₁₁.','secondary'),
('General Education','Science','medium','Which of the following is a strong acid?','[{"key":"A","text":"Acetic acid (CH₃COOH)"},{"key":"B","text":"Carbonic acid (H₂CO₃)"},{"key":"C","text":"Hydrochloric acid (HCl)"},{"key":"D","text":"Formic acid (HCOOH)"}]','C','Strong acids completely dissociate in water: HCl, HNO₃, H₂SO₄, HBr, HI, HClO₄, HClO₃. Acetic, carbonic, and formic acids are weak acids (partial dissociation).','secondary'),
('General Education','Science','medium','Isotopes of an element have the same:','[{"key":"A","text":"Mass number"},{"key":"B","text":"Number of neutrons"},{"key":"C","text":"Atomic number but different mass numbers"},{"key":"D","text":"Number of electrons and neutrons"}]','C','Isotopes are atoms of the same element (same number of protons/atomic number) with different numbers of neutrons (different mass numbers).','secondary'),
('General Education','Science','hard','In a galvanic cell, oxidation occurs at the:','[{"key":"A","text":"Cathode"},{"key":"B","text":"Anode"},{"key":"C","text":"Salt bridge"},{"key":"D","text":"Electrolyte"}]','B','In electrochemical cells, oxidation occurs at the anode (loss of electrons) and reduction occurs at the cathode (gain of electrons). Mnemonic: OIL RIG, AnOx RedCat.','secondary');
